 */
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'pixelart-xl'
  | (string & {});

/**
 * Settings for the PixelArt image generation model.
 */
export interface PixelArtImageSettings {
  /**
   * The size of the generated image (e.g. "512x512", "1024x1024").
   * If not set, the API's default size will be used.
   */
  size?: string;

  /**
   * The pixel-art style to apply to the generated image.
   * - "pixel": Classic pixel art look
   * - "retro": Retro 16-bit style
   * - "8bit": 8-bit console style
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density of the generated image. Higher values produce
   * finer-grained pixel art. Typical range: 1–16.
   */
  pixelDensity?: number;
}

